from adk import Agent
def detect_circular_delegation(callback_data):
    stack = callback_data.get('delegation_stack', [])
    current_agent = callback_data['agent_id']

    # Check if current agent appears twice in stack (cycle)
    if stack.count(current_agent) > 1:
        cycle_path = ' -> '.join(stack[stack.index(current_agent):] + [current_agent])
        print(f'🚨 CIRCULAR DELEGATION: {cycle_path}')
        return {'alert': 'circular_dependency', 'path': cycle_path}

    stack.append(current_agent)
    return {'delegation_stack': stack}

def check_model_consistency(callback_data):
    agents = callback_data.get('session_agents', {})
    model_versions = set()

    for agent_id, config in agents.items():
        model = config.get('model', 'unknown')
        model_versions.add(model)

    if len(model_versions) > 1:
        print(f'⚠️ MODEL INCONSISTENCY: {model_versions}')
        return {'alert': 'model_mismatch', 'models': list(model_versions)}
    return {'status': 'consistent'}

import hashlib
def monitor_session_state(callback_data):
    session_state = callback_data.get('session_state', {})
    state_str = str(sorted(session_state.items()))
    state_hash = hashlib.md5(state_str.encode()).hexdigest()

    prev_hash = callback_data.get('last_state_hash')
    if prev_hash and prev_hash != state_hash:
        print(f'🔍 STATE DRIFT DETECTED: {prev_hash[:8]} → {state_hash[:8]}')
        return {'alert': 'state_drift', 'hash_change': True}

    return {'last_state_hash': state_hash}

