from adk import Agent
class SafeDelegationAgent(Agent):
    def __init__(self, *args, max_delegations=5, **kwargs):
        super().__init__(*args, **kwargs)
        self.max_delegations = max_delegations

    async def before_delegate(self, target_agent, context):
        delegation_count = context.get('delegation_count', 0)
        if delegation_count >= self.max_delegations:
            return {'error': 'Max delegation depth exceeded', 'safe_response': 'Cannot delegate further'}
        context['delegation_count'] = delegation_count + 1
        return context

from adk import Workflow
class ConsistentModelWorkflow(Workflow):
    def __init__(self, model='gemini-1.5-pro'):
        super().__init__()
        self.default_model = model

    def add_agent(self, agent):
        agent.model = self.default_model
        super().add_agent(agent)
        print(f'✅ Agent {agent.name} configured with {self.default_model}')
        return self

